begin;
insert into public.feature_flags(key,enabled,description)values('memberships',false,'Account membership plans, purchases and renewals')on conflict(key)do nothing;
alter table public.profiles add column is_test_account boolean not null default false;

create table public.membership_plans(
 id uuid primary key default gen_random_uuid(),slug text not null unique check(slug~'^[a-z0-9]+(?:-[a-z0-9]+)*$'),name text not null check(char_length(name)between 3 and 100),description text not null check(char_length(description)between 20 and 1500),
 price_minor bigint not null check(price_minor>=0),currency text not null default'KES'check(currency~'^[A-Z]{3}$'),duration_months integer not null check(duration_months between 1 and 36),grace_days integer not null default 14 check(grace_days between 0 and 60),
 payment_mode text not null default'closed'check(payment_mode in('automatic','manual_review','closed')),status text not null default'draft'check(status in('draft','published','archived')),created_by uuid not null references auth.users(id)on delete restrict,created_at timestamptz not null default now(),updated_at timestamptz not null default now()
);
create table public.membership_periods(
 id uuid primary key default gen_random_uuid(),user_id uuid not null references auth.users(id)on delete restrict,plan_id uuid not null references public.membership_plans(id)on delete restrict,order_id uuid references public.orders(id)on delete restrict,
 renewed_from_id uuid references public.membership_periods(id)on delete set null,source text not null check(source in('purchase','manual_grant','event_included')),status text not null check(status in('scheduled','active','grace','expired','revoked')),
 starts_at timestamptz not null,ends_at timestamptz not null,grace_ends_at timestamptz not null,revoked_at timestamptz,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),constraint membership_period_window check(ends_at>starts_at and grace_ends_at>=ends_at)
);
create index membership_periods_user_idx on public.membership_periods(user_id,status,ends_at desc);create unique index membership_period_order_idx on public.membership_periods(order_id)where order_id is not null;create index membership_plans_catalog_idx on public.membership_plans(status,created_at);

alter table public.orders drop constraint if exists orders_order_type_check;alter table public.orders add constraint orders_order_type_check check(order_type in('event','course','membership'));
alter table public.orders drop constraint if exists order_context_present;alter table public.orders add constraint order_context_present check((order_type='event'and event_id is not null)or(order_type in('course','membership')and event_id is null));
alter table public.order_items add column membership_plan_id uuid references public.membership_plans(id)on delete restrict;
alter table public.order_items drop constraint if exists order_item_exactly_one_product;alter table public.order_items add constraint order_item_exactly_one_product check(num_nonnulls(ticket_type_id,course_id,membership_plan_id)=1);
alter table public.entitlements alter column order_id drop not null;alter table public.entitlements add column membership_period_id uuid references public.membership_periods(id)on delete cascade;
alter table public.entitlements drop constraint if exists entitlements_entitlement_type_check;alter table public.entitlements add constraint entitlements_entitlement_type_check check(entitlement_type in('event_access','member_onboarding','course_access','membership_access'));
create unique index entitlements_membership_period_idx on public.entitlements(user_id,membership_period_id,entitlement_type)where membership_period_id is not null;

alter table public.membership_plans enable row level security;alter table public.membership_periods enable row level security;
create policy "Members read published membership plans"on public.membership_plans for select to authenticated using(((exists(select 1 from public.profiles where id=auth.uid()and access_status in('active','dormant')))and status='published')or public.is_admin(array['super_admin']::public.app_role[]));
create policy "Members read own membership periods"on public.membership_periods for select to authenticated using(user_id=auth.uid()or public.is_admin(array['super_admin']::public.app_role[]));

create or replace function public.memberships_enabled()returns boolean language sql stable security definer set search_path=''as $$select coalesce((select enabled from public.feature_flags where key='memberships'),false)$$;
create or replace function public.save_membership_plan(p_plan_id uuid,p_slug text,p_name text,p_description text,p_price_minor bigint,p_currency text,p_duration integer,p_grace integer,p_payment_mode text,p_status text)
returns uuid language plpgsql security definer set search_path=''as $$declare saved uuid:=p_plan_id;begin if not public.is_admin(array['super_admin']::public.app_role[])then raise exception'Super admin required';end if;if p_payment_mode not in('automatic','manual_review','closed')or p_status not in('draft','published','archived')then raise exception'Unsupported plan configuration';end if;if p_plan_id is null then insert into public.membership_plans(slug,name,description,price_minor,currency,duration_months,grace_days,payment_mode,status,created_by)values(lower(trim(p_slug)),trim(p_name),trim(p_description),p_price_minor,upper(p_currency),p_duration,p_grace,p_payment_mode,p_status,auth.uid())returning id into saved;else update public.membership_plans set slug=lower(trim(p_slug)),name=trim(p_name),description=trim(p_description),price_minor=p_price_minor,currency=upper(p_currency),duration_months=p_duration,grace_days=p_grace,payment_mode=p_payment_mode,status=p_status,updated_at=now()where id=p_plan_id;if not found then raise exception'Plan not found';end if;end if;insert into public.audit_events(actor_id,action,target_type,target_id,metadata)values(auth.uid(),case when p_plan_id is null then'membership.plan_created'else'membership.plan_updated'end,'membership_plan',saved,jsonb_build_object('status',p_status,'price_minor',p_price_minor));return saved;end;$$;

create or replace function public.list_membership_catalog()
returns table(plan_id uuid,slug text,name text,description text,price_minor bigint,currency text,duration_months integer,grace_days integer,payment_mode text,status text,current_period_id uuid,current_status text,current_starts_at timestamptz,current_ends_at timestamptz,grace_ends_at timestamptz)
language plpgsql stable security definer set search_path=''as $$begin if auth.uid()is null then raise exception'Authentication required';end if;if not public.memberships_enabled()and not public.is_admin(array['super_admin']::public.app_role[])then raise exception'Memberships are not available yet';end if;return query select p.id,p.slug,p.name,p.description,p.price_minor,p.currency,p.duration_months,p.grace_days,p.payment_mode,p.status,mp.id,mp.status,mp.starts_at,mp.ends_at,mp.grace_ends_at from public.membership_plans p left join lateral(select x.*from public.membership_periods x where x.user_id=auth.uid()and x.status in('scheduled','active','grace')order by x.starts_at desc limit 1)mp on true where p.status='published'or public.is_admin(array['super_admin']::public.app_role[])order by p.price_minor;end;$$;

create or replace function public.create_membership_order(p_plan_id uuid,p_manual_reference text default null,p_manual_note text default null)
returns uuid language plpgsql security definer set search_path=''as $$declare target public.membership_plans%rowtype;saved uuid;next_status text;begin if not public.memberships_enabled()or auth.uid()is null then raise exception'Memberships are unavailable';end if;select*into target from public.membership_plans where id=p_plan_id and status='published'for share;if not found or target.payment_mode='closed'then raise exception'Membership checkout is closed';end if;if exists(select 1 from public.orders o join public.order_items i on i.order_id=o.id where o.user_id=auth.uid()and i.membership_plan_id=p_plan_id and o.status in('pending_payment','pending_review','paid','approved'))then raise exception'An active membership order already exists';end if;next_status:=case when target.payment_mode='automatic'then'pending_payment'else'pending_review'end;insert into public.orders(user_id,event_id,status,processing_mode,currency,subtotal_minor,total_minor,reservation_expires_at,order_type)values(auth.uid(),null,next_status,target.payment_mode,target.currency,target.price_minor,target.price_minor,case when target.payment_mode='automatic'then now()+interval'20 minutes'end,'membership')returning id into saved;insert into public.order_items(order_id,membership_plan_id,quantity,unit_price_minor,line_total_minor)values(saved,p_plan_id,1,target.price_minor,target.price_minor);if target.payment_mode='manual_review'then insert into public.manual_payment_reviews(order_id,submitted_reference,submitter_note)values(saved,nullif(trim(p_manual_reference),''),nullif(trim(p_manual_note),''));end if;insert into public.audit_events(actor_id,action,target_type,target_id,metadata)values(auth.uid(),'membership.order_created','order',saved,jsonb_build_object('plan_id',p_plan_id));return saved;end;$$;

create or replace function public.issue_membership_period(p_user_id uuid,p_plan_id uuid,p_order_id uuid,p_source text)
returns uuid language plpgsql security definer set search_path=''as $$declare plan public.membership_plans%rowtype;previous public.membership_periods%rowtype;period_start timestamptz;period_end timestamptz;saved uuid;begin select*into plan from public.membership_plans where id=p_plan_id;if not found then raise exception'Plan not found';end if;if p_order_id is not null then select id into saved from public.membership_periods where order_id=p_order_id;if saved is not null then return saved;end if;end if;select*into previous from public.membership_periods where user_id=p_user_id and status in('scheduled','active','grace')order by ends_at desc limit 1 for update;period_start:=greatest(coalesce(previous.ends_at,now()),now());period_end:=period_start+make_interval(months=>plan.duration_months);insert into public.membership_periods(user_id,plan_id,order_id,renewed_from_id,source,status,starts_at,ends_at,grace_ends_at)values(p_user_id,p_plan_id,p_order_id,previous.id,p_source,case when period_start>now()+interval'1 minute'then'scheduled'else'active'end,period_start,period_end,period_end+make_interval(days=>plan.grace_days))returning id into saved;insert into public.entitlements(user_id,membership_period_id,order_id,entitlement_type,metadata)values(p_user_id,saved,p_order_id,'membership_access',jsonb_build_object('source',p_source,'plan_id',p_plan_id))on conflict(user_id,membership_period_id,entitlement_type)where membership_period_id is not null do nothing;update public.profiles set access_status=case when access_status in('pending','onboarding','dormant')then'active'::public.member_access_status else access_status end,updated_at=now()where id=p_user_id;return saved;end;$$;

create or replace function public.fulfill_membership_order(p_order_id uuid,p_source text)returns void language plpgsql security definer set search_path=''as $$declare target public.orders%rowtype;plan_id uuid;begin select*into target from public.orders where id=p_order_id and order_type='membership'for update;if not found then raise exception'Membership order not found';end if;if target.status='fulfilled'then return;end if;if target.status not in('paid','approved')then raise exception'Order is not approved for fulfillment';end if;select membership_plan_id into plan_id from public.order_items where order_id=p_order_id;perform public.issue_membership_period(target.user_id,plan_id,target.id,'purchase');update public.orders set status='fulfilled',fulfilled_at=now(),updated_at=now()where id=p_order_id;perform public.enqueue_notification(target.user_id,'system','Membership confirmed','Your Her Africa Table membership is active or scheduled for renewal.','/membership','membership-access:'||target.id);end;$$;

create or replace function public.review_membership_order(p_order_id uuid,p_action text,p_note text)returns void language plpgsql security definer set search_path=''as $$begin if not public.is_admin(array['super_admin']::public.app_role[])then raise exception'Super admin required';end if;if p_action not in('approve','reject')then raise exception'Unsupported action';end if;update public.manual_payment_reviews set status=case when p_action='approve'then'approved'else'rejected'end,reviewer_id=auth.uid(),reviewer_note=nullif(trim(p_note),''),reviewed_at=now(),updated_at=now()where order_id=p_order_id and status='pending';if not found then raise exception'Pending review not found';end if;update public.orders set status=case when p_action='approve'then'approved'else'cancelled'end,updated_at=now()where id=p_order_id and order_type='membership';if not found then raise exception'Membership order not found';end if;if p_action='approve'then perform public.fulfill_membership_order(p_order_id,'manual_review');end if;insert into public.audit_events(actor_id,action,target_type,target_id,metadata)values(auth.uid(),'membership.manual_'||p_action,'order',p_order_id,jsonb_build_object('note',nullif(trim(p_note),'')));end;$$;

create or replace function public.grant_membership(p_user_email text,p_plan_id uuid,p_note text)returns uuid language plpgsql security definer set search_path=''as $$declare target uuid;saved uuid;begin if not public.is_admin(array['super_admin']::public.app_role[])then raise exception'Super admin required';end if;if char_length(trim(coalesce(p_note,'')))<5 then raise exception'Grant reason required';end if;select id into target from auth.users where lower(email)=lower(trim(p_user_email));if target is null then raise exception'User not found';end if;saved:=public.issue_membership_period(target,p_plan_id,null,'manual_grant');insert into public.audit_events(actor_id,action,target_type,target_id,metadata)values(auth.uid(),'membership.access_granted','membership_period',saved,jsonb_build_object('member_id',target,'note',trim(p_note)));return saved;end;$$;

create or replace function public.reconcile_membership_periods()returns table(promoted integer,graced integer,expired integer,dormant integer)language plpgsql security definer set search_path=''as $$declare p integer;g integer;e integer;d integer;begin if coalesce(auth.jwt()->>'role','')<>'service_role'and not public.is_admin(array['super_admin']::public.app_role[])then raise exception'Service or Super Admin required';end if;with x as(update public.membership_periods set status='active',updated_at=now()where status='scheduled'and starts_at<=now()returning 1)select count(*)into p from x;with x as(update public.membership_periods set status='grace',updated_at=now()where status='active'and ends_at<=now()and grace_ends_at>now()returning 1)select count(*)into g from x;with x as(update public.membership_periods set status='expired',updated_at=now()where status in('active','grace')and grace_ends_at<=now()returning user_id)select count(*)into e from x;with x as(update public.profiles pr set access_status='dormant',updated_at=now()where pr.access_status='active'and not pr.is_test_account and not exists(select 1 from public.membership_periods mp where mp.user_id=pr.id and mp.status in('active','grace')and mp.grace_ends_at>now())and exists(select 1 from public.membership_periods anyp where anyp.user_id=pr.id)returning 1)select count(*)into d from x;insert into public.audit_events(actor_id,action,target_type,metadata)values(auth.uid(),'membership.reconciled','membership_periods',jsonb_build_object('promoted',p,'graced',g,'expired',e,'dormant',d));return query select p,g,e,d;end;$$;

create or replace function public.list_memberships_admin()returns table(period_id uuid,user_id uuid,email text,display_name text,is_test_account boolean,plan_id uuid,plan_name text,status text,source text,starts_at timestamptz,ends_at timestamptz,grace_ends_at timestamptz,order_id uuid)language plpgsql stable security definer set search_path=''as $$begin if not public.is_admin(array['super_admin']::public.app_role[])then raise exception'Super admin required';end if;return query select mp.id,mp.user_id,u.email::text,p.display_name,p.is_test_account,mp.plan_id,pl.name,mp.status,mp.source,mp.starts_at,mp.ends_at,mp.grace_ends_at,mp.order_id from public.membership_periods mp join auth.users u on u.id=mp.user_id join public.profiles p on p.id=mp.user_id join public.membership_plans pl on pl.id=mp.plan_id order by mp.created_at desc;end;$$;
create or replace function public.list_membership_orders()returns table(order_id uuid,reference text,plan_id uuid,plan_name text,user_id uuid,email text,display_name text,status text,total_minor bigint,currency text,submitted_reference text,submitter_note text,created_at timestamptz)language plpgsql stable security definer set search_path=''as $$begin if not public.is_admin(array['super_admin']::public.app_role[])then raise exception'Super admin required';end if;return query select o.id,o.reference,i.membership_plan_id,p.name,o.user_id,u.email::text,pr.display_name,o.status,o.total_minor,o.currency,m.submitted_reference,m.submitter_note,o.created_at from public.orders o join public.order_items i on i.order_id=o.id join public.membership_plans p on p.id=i.membership_plan_id join auth.users u on u.id=o.user_id left join public.profiles pr on pr.id=o.user_id left join public.manual_payment_reviews m on m.order_id=o.id where o.order_type='membership'order by o.created_at desc;end;$$;
create or replace function public.mark_test_account(p_user_id uuid,p_display_name text)returns void language plpgsql security definer set search_path=''as $$begin if not public.is_admin(array['super_admin']::public.app_role[])then raise exception'Super admin required';end if;update public.profiles set display_name=trim(p_display_name),is_test_account=true,access_status='active',onboarding_completed_at=coalesce(onboarding_completed_at,now()),profile_completion=100,updated_at=now()where id=p_user_id;if not found then raise exception'Profile not found';end if;insert into public.audit_events(actor_id,action,target_type,target_id)values(auth.uid(),'test_account.marked','profile',p_user_id);end;$$;

create or replace function public.notify_order_event()returns trigger language plpgsql security definer set search_path=''as $$declare item_title text;target_href text;begin if tg_op='UPDATE'and old.status is not distinct from new.status then return new;end if;if new.order_type='event'then select title,'/orders/'||new.reference into item_title,target_href from public.events where id=new.event_id;elsif new.order_type='course'then select c.title,'/learning/'||c.slug into item_title,target_href from public.order_items i join public.courses c on c.id=i.course_id where i.order_id=new.id;else select p.name,'/membership'into item_title,target_href from public.order_items i join public.membership_plans p on p.id=i.membership_plan_id where i.order_id=new.id;end if;perform public.enqueue_notification(new.user_id,'registration',case new.order_type when'membership'then'Membership update'when'course'then'Learning order update'else'Registration update'end,coalesce(item_title,'Your order')||' is now '||replace(new.status,'_',' ')||'.',coalesce(target_href,'/orders/'||new.reference),'order-status:'||new.id||':'||new.status);return new;end;$$;

create or replace function public.process_paystack_payment(p_provider_event_id text,p_event_type text,p_reference text,p_status text,p_amount_minor bigint,p_currency text,p_payload jsonb,p_signature_verified boolean)returns text language plpgsql security definer set search_path=''as $$declare target public.orders%rowtype;processed timestamptz;begin if auth.role()<>'service_role'then raise exception'Service role required';end if;if not p_signature_verified then raise exception'Provider signature or server verification required';end if;insert into public.payment_events(provider,provider_event_id,event_type,signature_verified,payload)values('paystack',p_provider_event_id,p_event_type,true,coalesce(p_payload,'{}'))on conflict(provider,provider_event_id)do nothing;select processed_at into processed from public.payment_events where provider='paystack'and provider_event_id=p_provider_event_id for update;if processed is not null then return'already_processed';end if;select*into target from public.orders where reference=p_reference for update;if not found then update public.payment_events set error_message='Order reference not found',processed_at=now()where provider='paystack'and provider_event_id=p_provider_event_id;return'order_not_found';end if;if target.total_minor<>p_amount_minor or target.currency<>upper(p_currency)then update public.payment_events set error_message='Amount or currency mismatch',processed_at=now()where provider='paystack'and provider_event_id=p_provider_event_id;return'amount_mismatch';end if;insert into public.payment_attempts(order_id,provider,provider_reference,amount_minor,currency,status,provider_response)values(target.id,'paystack',p_reference,p_amount_minor,upper(p_currency),case when p_status='success'then'success'when p_status in('failed','abandoned','reversed')then p_status else'pending'end,coalesce(p_payload,'{}'))on conflict(provider_reference)do update set status=excluded.status,provider_response=excluded.provider_response,updated_at=now();if p_status='success'then update public.orders set status='paid',updated_at=now()where id=target.id and status in('pending_payment','paid');if target.status<>'fulfilled'then if target.order_type='course'then perform public.fulfill_course_order(target.id,'paystack_verified');elsif target.order_type='membership'then perform public.fulfill_membership_order(target.id,'paystack_verified');else perform public.fulfill_registration_order(target.id,'paystack_verified');end if;end if;elsif p_status in('failed','abandoned')then update public.orders set status='expired',updated_at=now()where id=target.id and status='pending_payment';if target.order_type='event'then update public.registration_requests set status='cancelled',updated_at=now()where order_id=target.id and status='pending_payment';end if;elsif p_status='reversed'then update public.orders set status='refunded',updated_at=now()where id=target.id;update public.entitlements set status='revoked',revoked_at=now()where order_id=target.id and status='active';if target.order_type='event'then update public.event_memberships set status='cancelled',updated_at=now()where order_id=target.id;elsif target.order_type='course'then update public.course_enrollments set status='revoked',updated_at=now()where order_id=target.id;else update public.membership_periods set status='revoked',revoked_at=now(),updated_at=now()where order_id=target.id;end if;end if;update public.payment_events set processed_at=now(),error_message=null where provider='paystack'and provider_event_id=p_provider_event_id;insert into public.audit_events(action,target_type,target_id,metadata)values('payment.paystack_'||p_status,'order',target.id,jsonb_build_object('order_type',target.order_type,'provider_event_id',p_provider_event_id));return case when p_status='success'then'fulfilled'else p_status end;exception when others then update public.payment_events set error_message=sqlerrm where provider='paystack'and provider_event_id=p_provider_event_id;raise;end;$$;

revoke all on function public.memberships_enabled()from public;grant execute on function public.memberships_enabled()to authenticated;revoke all on function public.save_membership_plan(uuid,text,text,text,bigint,text,integer,integer,text,text)from public;grant execute on function public.save_membership_plan(uuid,text,text,text,bigint,text,integer,integer,text,text)to authenticated;revoke all on function public.list_membership_catalog()from public;grant execute on function public.list_membership_catalog()to authenticated;revoke all on function public.create_membership_order(uuid,text,text)from public;grant execute on function public.create_membership_order(uuid,text,text)to authenticated;revoke all on function public.issue_membership_period(uuid,uuid,uuid,text)from public;revoke all on function public.fulfill_membership_order(uuid,text)from public;revoke all on function public.review_membership_order(uuid,text,text)from public;grant execute on function public.review_membership_order(uuid,text,text)to authenticated;revoke all on function public.grant_membership(text,uuid,text)from public;grant execute on function public.grant_membership(text,uuid,text)to authenticated;revoke all on function public.reconcile_membership_periods()from public;grant execute on function public.reconcile_membership_periods()to authenticated,service_role;revoke all on function public.list_memberships_admin()from public;grant execute on function public.list_memberships_admin()to authenticated;revoke all on function public.list_membership_orders()from public;grant execute on function public.list_membership_orders()to authenticated;revoke all on function public.mark_test_account(uuid,text)from public;grant execute on function public.mark_test_account(uuid,text)to authenticated;revoke all on function public.process_paystack_payment(text,text,text,text,bigint,text,jsonb,boolean)from public;grant execute on function public.process_paystack_payment(text,text,text,text,bigint,text,jsonb,boolean)to service_role;
-- Renewal lifecycle hardening.
create or replace function public.create_membership_order(p_plan_id uuid,p_manual_reference text default null,p_manual_note text default null)
returns uuid language plpgsql security definer set search_path=''as $$
declare target public.membership_plans%rowtype;saved uuid;next_status text;
begin
 if not public.memberships_enabled()or auth.uid()is null then raise exception'Memberships are unavailable';end if;
 if not exists(select 1 from public.profiles where id=auth.uid()and access_status in('active','dormant'))then raise exception'Approved member account required';end if;
 select*into target from public.membership_plans where id=p_plan_id and status='published'for share;
 if not found or target.payment_mode='closed'then raise exception'Membership checkout is closed';end if;
 if exists(select 1 from public.orders o join public.order_items i on i.order_id=o.id where o.user_id=auth.uid()and i.membership_plan_id=p_plan_id and o.status in('pending_payment','pending_review','paid','approved'))then raise exception'An active membership order already exists';end if;
 next_status:=case when target.payment_mode='automatic'then'pending_payment'else'pending_review'end;
 insert into public.orders(user_id,event_id,status,processing_mode,currency,subtotal_minor,total_minor,reservation_expires_at,order_type)values(auth.uid(),null,next_status,target.payment_mode,target.currency,target.price_minor,target.price_minor,case when target.payment_mode='automatic'then now()+interval'20 minutes'end,'membership')returning id into saved;
 insert into public.order_items(order_id,membership_plan_id,quantity,unit_price_minor,line_total_minor)values(saved,p_plan_id,1,target.price_minor,target.price_minor);
 if target.payment_mode='manual_review'then insert into public.manual_payment_reviews(order_id,submitted_reference,submitter_note)values(saved,nullif(trim(p_manual_reference),''),nullif(trim(p_manual_note),''));end if;
 insert into public.audit_events(actor_id,action,target_type,target_id,metadata)values(auth.uid(),'membership.order_created','order',saved,jsonb_build_object('plan_id',p_plan_id));return saved;
end;$$;

create or replace function public.issue_membership_period(p_user_id uuid,p_plan_id uuid,p_order_id uuid,p_source text)
returns uuid language plpgsql security definer set search_path=''as $$
declare plan public.membership_plans%rowtype;previous public.membership_periods%rowtype;period_start timestamptz;period_end timestamptz;saved uuid;
begin
 perform pg_advisory_xact_lock(hashtextextended(p_user_id::text,0));
 select*into plan from public.membership_plans where id=p_plan_id;if not found then raise exception'Plan not found';end if;
 if p_order_id is not null then select id into saved from public.membership_periods where order_id=p_order_id;if saved is not null then return saved;end if;end if;
 select*into previous from public.membership_periods where user_id=p_user_id and status in('scheduled','active','grace')order by ends_at desc limit 1 for update;
 period_start:=greatest(coalesce(previous.ends_at,now()),now());period_end:=period_start+make_interval(months=>plan.duration_months);
 insert into public.membership_periods(user_id,plan_id,order_id,renewed_from_id,source,status,starts_at,ends_at,grace_ends_at)values(p_user_id,p_plan_id,p_order_id,previous.id,p_source,case when period_start>now()+interval'1 minute'then'scheduled'else'active'end,period_start,period_end,period_end+make_interval(days=>plan.grace_days))returning id into saved;
 insert into public.entitlements(user_id,membership_period_id,order_id,entitlement_type,metadata)values(p_user_id,saved,p_order_id,'membership_access',jsonb_build_object('source',p_source,'plan_id',p_plan_id))on conflict(user_id,membership_period_id,entitlement_type)where membership_period_id is not null do nothing;
 update public.profiles set access_status=case when access_status in('pending','onboarding','dormant')then(case when onboarding_completed_at is null then'onboarding'::public.member_access_status else'active'::public.member_access_status end)else access_status end,updated_at=now()where id=p_user_id;
 return saved;
end;$$;

comment on table public.membership_periods is'Account membership terms with scheduled renewal, grace and dormant reconciliation.';comment on column public.profiles.is_test_account is'Explicit production test identity excluded from operational metrics and automated dormancy.';
commit;
